+                            .dipping_rising => return 0x1EA3, // ả.
+                            .rising_glottalized => return 0x00E3, // ã.
+                            .falling_glottalized => return 0x1EA1, // ạ.
+                        }
+                    },
+                    .breve => {
+                        switch (self.tone) {
